mapper.select:
SELECT A.* ,(CASE WHEN A.PROGRESS_CD < 4210 OR A.PROGRESS_CD = '4220' THEN 'true' ELSE 'false' END) AS ATT_FILE_EDITABLE FROM ( SELECT TCCT.BUYER_CD , TCCT.BUNDLE_NUM , TCCT.CONT_NUM , TCCT.CONT_CNT , TCCT.CONT_DESC , TCCT.CONT_REQ_CD , TCCT.CUR , TCCT.CONT_AMT , TCCT.CONT_USER_ID , GETUSERNAME(TCCT.GATE_CD, TCCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , TCRL.CONTRACT_TEXT_NUM , TCRL.CONTRACT_TEXT , TCRL.FORM_NUM AS MAIN_FORM_NUM , TCCT.CERT_TYPE , TCCT.AUTO_RENEW_FLAG , TCCT.CONT_RMK ,(SELECT MAX(PROGRESS_CD) FROM STOCTCCT WHERE GATE_CD = TCCT.GATE_CD AND BUYER_CD = TCCT.BUYER_CD AND BUNDLE_NUM = TCCT.BUNDLE_NUM
AND CONT_NUM = TCCT.CONT_NUM AND CONT_CNT = TCCT.CONT_CNT
AND DEL_FLAG = '0') AS PROGRESS_CD , TCCT.SIGN_STATUS , TCCT.ATT_FILE_NUM , TCCT.VENDOR_ATT_FILE_NUM
,(SELECT (MAX(SIGN_DATE), 'YYYYMMDD') FROM STOCECSV WHERE GATE_CD = TCCT.GATE_CD AND BUYER_CD = TCCT.BUYER_CD AND CONT_NUM = TCCT.CONT_NUM AND CONT_CNT = TCCT.CONT_CNT AND USER_TYPE = 'B' AND ROWNUM = 1) AS BUYER_SIGN_DATE ,(SELECT (MAX(SIGN_DATE), 'YYYYMMDD') FROM STOCECSV WHERE GATE_CD = TCCT.GATE_CD AND BUYER_CD = TCCT.BUYER_CD AND CONT_NUM = TCCT.CONT_NUM AND CONT_CNT = TCCT.CONT_CNT AND VENDOR_CD = TCCT.VENDOR_CD AND USER_TYPE = 'S' AND ROWNUM = 1) AS VENDOR_SIGN_DATE , TCRL.FORM_NUM , TCCT.APP_DOC_NUM , TCCT.APP_DOC_CNT , ECCF.CONT_TYPE , TCCT.JIKJONG_TYPE FROM STOCTCCT TCCT LEFT JOIN STOCTCRL TCRL ON (TCCT.GATE_CD = TCRL.GATE_CD AND TCCT.BUYER_CD = TCRL.BUYER_CD AND TCCT.CONT_NUM = TCRL.CONT_NUM AND TCCT.CONT_CNT = TCRL.CONT_CNT AND TCRL.FORM_SQ = '0' AND TCRL.DEL_FLAG = '0') LEFT JOIN STOCECCF ECCF ON (TCRL.GATE_CD = ECCF.GATE_CD /** 2020.08.11 제외 AND TCRL.BUYER_CD = ECCF.BUYER_CD*/ AND TCRL.FORM_NUM = ECCF.FORM_NUM) WHERE TCCT.GATE_CD = #{ses.gateCd} AND TCCT.DEL_FLAG = '0' AND ECCF.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})
AND TCCT.CONT_NUM = #{CONT_NUM} AND TCCT.CONT_CNT = #{CONT_CNT}
AND TCCT.APP_DOC_NUM = #{APP_DOC_NUM} AND TCCT.APP_DOC_CNT = #{APP_DOC_CNT}
AND TCCT.BUNDLE_NUM = #{BUNDLE_NUM}
AND ROWNUM = 1
) A WHERE 1 = 1

SELECT X.* FROM ( SELECT ECCR.GATE_CD , TCRL.CONT_NUM , ECF2.FORM_TYPE ,GETCODENAME(ECF2.GATE_CD, 'M078', ECF2.FORM_TYPE, #{ses.langCd}) AS FORM_TYPE_NM , ECCR.FORM_NUM , ECCR.REL_FORM_NUM , ECCR.REL_FORM_SQ ,(ECCR.DEFAULT_FLAG, '0') AS DEFAULT_FLAG ,(ECCR.REQUIRE_FLAG, '0') AS REQUIRE_FLAG , ECF2.FORM_NM AS REL_FORM_NM , ECF2.FORM_TEXT_NUM , ECF2.FORM_TEXT ,(CASE WHEN TCRL.FORM_NUM IS NOT NULL THEN '1' ELSE '0' END) AS EXISTS_FLAG , ECF2.CONT_TYPE AS CONTRACT_FORM_TYPE ,(TCRL.REQUIRE_FLAG, '0') AS TCRL_REQUIRE_FLAG , ECF2.FORM_FILE_NM , TCRL.FORM_SQ FROM STOCECCF ECCF JOIN STOCECCR ECCR ON (ECCF.GATE_CD = ECCR.GATE_CD AND ECCF.FORM_NUM = ECCR.FORM_NUM AND ECCR.DEL_FLAG = '0') JOIN STOCECCF ECF2 ON (ECCR.GATE_CD = ECF2.GATE_CD AND ECCR.REL_FORM_NUM = ECF2.FORM_NUM AND ECF2.SIGN_STATUS = 'E' AND ECF2.BUYER_CD = #{ses.companyCd}
AND ECF2.DEL_FLAG = '0' AND ECF2.USE_FLAG = '1') LEFT JOIN STOCTCRL TCRL ON (ECCR.GATE_CD = TCRL.GATE_CD AND ECCR.REL_FORM_NUM = TCRL.FORM_NUM
AND TCRL.CONT_NUM = #{PRE_CONT_NUM} AND TCRL.CONT_CNT = #{PRE_CONT_CNT}
AND TCRL.CONT_NUM = #{CONT_NUM} AND TCRL.CONT_CNT = #{CONT_CNT}
AND TCRL.FORM_SQ > 0 -- 부서식 AND TCRL.DEL_FLAG = '0') WHERE ECCF.GATE_CD = #{ses.gateCd} AND ECCF.FORM_NUM = #{FORM_NUM} AND ECCF.SIGN_STATUS = 'E' AND ECCF.DEL_FLAG = '0' AND ECCF.BUYER_CD = #{ses.companyCd}
AND UPPER(ECF2.FORM_NM) LIKE '%' UPPER(#{ADD_SEARCH}) '%'
AND ECCF.BUNDLE_FLAG = '1' --일괄계약 여부
) X WHERE 1 = 1 ORDER BY X.CONT_NUM , X.TCRL_REQUIRE_FLAG DESC , X.REQUIRE_FLAG DESC , X.DEFAULT_FLAG DESC , X.FORM_TYPE , X.REL_FORM_SQ , X.REL_FORM_NM

mapper.insert:
        INSERT INTO STOCTCCT (
        	  GATE_CD
			, BUYER_CD
			, DEPT_CD
			, CONT_NUM
			, CONT_CNT
			, REG_DATE
			, REG_USER_ID
