			, CONT_DATE
			, CONT_START_DATE
			, CONT_END_DATE
			, CONT_USER_ID
			, USER_ID
			, USER_NM
			, BIRTH_DATE
			, PHONE_NUM
			, JIKMU_NAME
			, BUSINESS
			, POSITION
