			, JOB_PAY
			, JOB_PAY_RMKS
			, EXTEND_PAY
			, EXTEND_PAY_RMKS
			, FOOD_PAY
			, FOOD_PAY_RMKS
			, WORK_PAY
			, WORK_PAY_RMKS
			, NIGHT_PAY
			, NIGHT_PAY_RMKS
			, ETC_PAY
