			, ETC_PAY2_RMKS
			, CONT_DESC
			, CONT_TYPE
			, ATT_FILE_NUM
			, VENDOR_ATT_FILE_NUM
			, SIGN_STATUS
			, BUNDLE_NUM
			, K_ADDR
			, SEND_YN
			, G_ADDR1
			, CUST_NAME
			, SUBCUST_NAME
			, JIKJONG_TYPE       


        )
        VALUES (
      		  #{ses.gateCd}
			, #{ses.companyCd}
			, #{ses.deptCd}
			, #{CONT_NUM}
			, #{CONT_CNT}
			, SYSDATE
			, #{ses.userId}
			, SYSDATE
			, #{ses.userId}
			, '0'
			, #{PROGRESS_CD}
			,(#{CONT_DATE}, SYSDATE)
			, #{CONT_START_DATE}
			, #{CONT_END_DATE}
			, #{ses.userId}
			, #{USER_ID}
			, #{USER_NM}
			, TO_CHAR(TO_DATE(#{BIRTH_DATE}),'YYYY-MM-DD')
			, #{CELL_NUM}
			, #{JIKMU_NAME}
			, #{JIKMU_NAME}
			, #{POSITION}
			, #{G_PLACE}
			, #{WORK_TIME_START}
			, #{WORK_TIME_END}
			, #{REST_TIME}
			, #{SPECIAL_CONDITION}
		    , #{WORK_CONDITION}
			, #{REST_CONDITION}
			, DECODE(#{WORKER_PAY_AMT},'null',0, TO_NUMBER(#{WORKER_PAY_AMT}))
			, DECODE(#{BASE_PAY},'null',0, TO_NUMBER(#{BASE_PAY}))
			, #{BASE_PAY_RMKS}
			, DECODE(#{LICENSE_PAY},'null',0, TO_NUMBER(#{LICENSE_PAY})) 
			, #{LICENSE_PAY_RMKS}
			, DECODE(#{JOB_PAY},'null',0, TO_NUMBER(#{JOB_PAY}))
			, #{JOB_PAY_RMKS}
			, DECODE(#{EXTEND_PAY},'null',0, TO_NUMBER(#{EXTEND_PAY})) 
			, #{EXTEND_PAY_RMKS}
			, DECODE(#{FOOD_PAY},'null',0, TO_NUMBER(#{FOOD_PAY})) 
			, #{FOOD_PAY_RMKS}    
			, DECODE(#{WORK_PAY},'null',0, TO_NUMBER(#{WORK_PAY}))          
			, #{WORK_PAY_RMKS}    
			, DECODE(#{NIGHT_PAY},'null',0, TO_NUMBER(#{NIGHT_PAY}))        
			, #{NIGHT_PAY_RMKS}
			, DECODE(#{ETC_PAY},'null',0, TO_NUMBER(#{ETC_PAY}))        
			, #{ETC_PAY_RMKS}
		    , DECODE(#{ETC_PAY2},'null',0, TO_NUMBER(#{ETC_PAY2}))        
			, #{ETC_PAY2_RMKS}
			, #{CONT_DESC}
			, #{CONT_TYPE}
			, #{ATT_FILE_NUM}
			, #{EMP_ATT_FILE_NUM}
			, #{SIGN_STATUS}       
		    , #{BUNDLE_NUM}
		    , #{K_ADDR}
		    , '0' 
		    , #{G_ADDR1}       
		    , #{CUST_NAME}  
			, #{SUBCUST_NAME}   
			, #{JIKJONG_TYPE}         

			)

        INSERT INTO STOCTCRL (
			   GATE_CD
			 , BUYER_CD
			 , CONT_NUM
			 , CONT_CNT
			 , FORM_NUM
			 , REG_DATE
			 , REG_USER_ID
			 , MOD_DATE
			 , MOD_USER_ID
			 , DEL_FLAG
			 , REQUIRE_FLAG
			 , FORM_SQ
			 , CONTRACT_TEXT_NUM
			 , FORM_CHECK_FLAG
			 , CONTRACT_TEXT
		) VALUES (
			   #{ses.gateCd}
			 , #{ses.companyCd}
			 , #{CONT_NUM}
			 , #{CONT_CNT}
			 , #{FORM_NUM}
			 , SYSDATE
			 , #{ses.userId}
			 , SYSDATE
			 , #{ses.userId}
			 , '0'
			 , #{REQUIRE_FLAG}
			 , #{FORM_SQ}
			 , #{CONTRACT_TEXT_NUM}
			 , #{FORM_CHECK_FLAG}
			 , #{CONTRACT_TEXT}
		)

        INSERT INTO STOCTCRL (
			   GATE_CD
			 , BUYER_CD
			 , CONT_NUM
			 , CONT_CNT
			 , FORM_NUM
			 , REG_DATE
			 , REG_USER_ID
			 , MOD_DATE
			 , MOD_USER_ID
			 , DEL_FLAG
			 , REQUIRE_FLAG
			 , FORM_SQ
			 , CONTRACT_TEXT_NUM
			 , FORM_CHECK_FLAG
			 , CONTRACT_TEXT
		) VALUES (
			   #{ses.gateCd}
			 , #{ses.companyCd}
			 , #{CONT_NUM}
			 , #{CONT_CNT}
			 , #{REL_FORM_NUM}
			 , SYSDATE
			 , #{ses.userId}
			 , SYSDATE
			 , #{ses.userId}
			 , '0'
			 , #{REQUIRE_FLAG}
			 , (SELECT (MAX(FORM_SQ), 0) + 1
			 	  FROM STOCTCRL
				 WHERE GATE_CD  = #{ses.gateCd}
				   AND BUYER_CD = #{ses.companyCd}
				   AND CONT_NUM = #{CONT_NUM}
				   AND CONT_CNT = #{CONT_CNT})
			 , #{CONTRACT_TEXT_NUM}
			 , #{FORM_CHECK_FLAG}
			 , #{CONTRACT_TEXT}
		)

