UPDATE STOCTCCT
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , PROGRESS_CD = #{PROGRESS_CD}
	 , SIGN_STATUS = #{SIGN_STATUS}
 WHERE GATE_CD    = #{ses.gateCd}
   AND BUYER_CD   = #{ses.companyCd}
   AND BUNDLE_NUM = #{BUNDLE_NUM}
   AND DEL_FLAG   = '0'

        UPDATE STOCTCCT
		   SET APP_DOC_NUM = #{APP_DOC_NUM}
			 , APP_DOC_CNT = CASE WHEN #{APP_DOC_CNT} = '' THEN NULL ELSE #{APP_DOC_CNT} END
		 WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{ses.companyCd}
		   AND CONT_NUM = #{CONT_NUM}
		   AND CONT_CNT = #{CONT_CNT}
		   AND DEL_FLAG = '0'

		UPDATE STOCTCCT
		   SET MOD_DATE    = SYSDATE
			 , MOD_USER_ID = #{ses.userId}
			 , PDF_ATT_FILE_NUM = #{UUID}
		 WHERE GATE_CD     = #{ses.gateCd}
		   AND BUYER_CD    = (#{BUYER_CD}, #{ses.companyCd})
		   AND CONT_NUM    = #{CONT_NUM}
           AND CONT_CNT    = #{CONT_CNT}

