	    AND TCCT.BUNDLE_NUM = #{BUNDLE_NUM}

	    AND TCCT.CONT_NUM = #{CONT_NUM}
	    AND TCCT.CONT_CNT = #{CONT_CNT}
	    AND TCCT.DEL_FLAG = '0'

