		UPDATE STOCTCCT
		   SET MOD_DATE    = SYSDATE
			 , MOD_USER_ID = #{ses.userId}
			 , VENDOR_ATT_FILE_NUM = #{EMP_ATT_FILE_NUM}
		 WHERE GATE_CD     = #{ses.gateCd}
		   AND BUYER_CD    = (#{BUYER_CD}, #{ses.companyCd})
		   AND CONT_NUM    = #{CONT_NUM}
           AND CONT_CNT    = #{CONT_CNT}

		UPDATE STOCTCRL TCRL
		   SET MOD_DATE = SYSDATE
			 , MOD_USER_ID = #{ses.userId}
			 , DEL_FLAG = '1'
		 WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{ses.companyCd}


		   AND EXISTS (SELECT 1 FROM STOCTCCT
                        WHERE GATE_CD    = TCRL.GATE_CD
                          AND BUYER_CD   = TCRL.BUYER_CD
                          AND CONT_NUM   = TCRL.CONTR_NUM
                          AND CONT_CNT   = TCRL.CONT_CNT
                          AND BUNDLE_NUM = #{BUNDLE_NUM})


		   AND TCRL.CONT_NUM = #{CONT_NUM}
		   AND TCRL.CONT_CNT = #{CONT_CNT}

